PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?team(COUNT(?competition) AS ?wins) WHERE {
  VALUES ?team {
    wd:Q2521385 wd:Q249679 wd:Q2272176
  }
  ?team wdt:P1344 ?competition
}
GROUP BY ?team
ORDER BY DESC(?wins)
LIMIT 1
OFFSET 1

